public void testDateWithCombinedPatternAndLocale() throws Exception
    {
        ObjectMapper mapper = new ObjectMapper();
        // @JsonFormat with both pattern and locale => STRING shape
        mapper.enable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS);

        class DateWithPatternAndLocale {
            @JsonFormat(pattern="yyyy-MM-dd", locale="en_US")
            public Date date;
            public DateWithPatternAndLocale(long timestamp) {
                this.date = new Date(timestamp);
            }
        }

        String json = mapper.writeValueAsString(new DateWithPatternAndLocale(0L));
        assertEquals(aposToQuotes("{'date':'1970-01-01'}"), json);
    }

public void testDateWithCombinedPatternAndTimezone() throws Exception
    {
        ObjectMapper mapper = new ObjectMapper();
        // @JsonFormat with both pattern and timezone => STRING shape
        mapper.enable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS);

        class DateWithPatternAndTimezone {
            @JsonFormat(pattern="yyyy-MM-dd HH:mm:ss", timezone="America/New_York")
            public Date date;
            public DateWithPatternAndTimezone(long timestamp) {
                this.date = new Date(timestamp);
            }
        }

        String json = mapper.writeValueAsString(new DateWithPatternAndTimezone(0L));
        assertTrue(json.contains("1969-12-31") || json.contains("1970-01-01"));
    }

public void testDateWithLocaleAndTimezone() throws Exception
    {
        ObjectMapper mapper = new ObjectMapper();
        // @JsonFormat with both locale and timezone => STRING shape
        mapper.enable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS);

        class DateWithLocaleAndTimezone {
            @JsonFormat(locale="en_GB", timezone="Europe/London")
            public Date date;
            public DateWithLocaleAndTimezone(long timestamp) {
                this.date = new Date(timestamp);
            }
        }

        String json = mapper.writeValueAsString(new DateWithLocaleAndTimezone(0L));
        assertEquals(aposToQuotes("{'date':'1970-01-01T01:00:00.000+0100'}"), json);
    }
